#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long curMax, curMin, x;
        for(int i=0;i<N;i++){
            scanf("%lld", &x);
            if(i==0){
                curMax = curMin = x;
            }else{
                if(x >= curMax){
                    if(x > curMax) curMax = x;
                }else if(x <= curMin){
                    if(x < curMin) curMin = x;
                }else{
                    // consume remaining inputs of this test case
                    for(int j=i+1;j<N;j++) scanf("%lld", &x);
                    printf("NO\n");
                    goto nextcase;
                }
            }
        }
        printf("YES\n");
        nextcase: ;
    }
    return 0;
}

