import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        n = int(next(it))
        cur_max = cur_min = int(next(it))
        ok = True
        for i in range(1, n):
            b = int(next(it))
            if not ok:
                continue
            if b >= cur_max:
                if b > cur_max:
                    cur_max = b
            elif b <= cur_min:
                if b < cur_min:
                    cur_min = b
            else:
                ok = False
        out_lines.append('YES' if ok else 'NO')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

